mapper.update:
UPDATE chat_messages
SET
	message_status = 'DELETED',
	deleted_at = NOW(),
	deleted_by = #{requesterUserId}
WHERE room_id = #{roomId}
  AND message_id = #{messageId}
  AND message_status = 'ACTIVE'

